import clsx from 'clsx';
import {
  type PropsWithChildren,
  forwardRef,
  useEffect,
  useRef,
  type MouseEvent as ReactMouseEvent,
} from 'react';
import { createPortal } from 'react-dom';

import { chartTooltip, wrapper } from './ChartTooltip.sty.js';
import { useMergeRefs } from '../../../../../core/hooks/useMergeRefs.js';
import type { StylingProps } from '../../../../../core/types/styling-props.js';
import { useDataDtrumContext } from '../../../context/DataDtrumContext.js';
import type { Point } from '../../../types/point.js';
import { isTouchableDevice } from '../../../utils/is-touchable-device.js';
import {
  ActionSelectionContext,
  ActionSelectionDetails,
} from '../context/ActionSelectionContext.js';
import { ChartTooltipMetadataContext } from '../context/ChartTooltipMetadataContext.js';
import { useChartTooltip } from '../shared/hooks/useChartTooltip.js';
import {
  ChartTooltipSlots,
  ChartTooltipAtoms,
  ChartTooltipTemplate,
} from '../types/ChartTooltip.config.js';

/** @internal */
export interface ChartTooltipProps extends StylingProps {
  /**
   * Indicates the location of the mouse in the browser window.
   */
  position: Point;
  /**
   * Indicates if the tooltip should be pinned or not.
   * @defaultValue false
   */
  pinned?: boolean;
  /**
   * If true, the tooltip position will update even when pinned.
   * For scroll-responsive tooltips.
   * @defaultValue false
   */
  updatePositionWhenPinned?: boolean;
  onMouseLeave?: (event: ReactMouseEvent) => void;
  actionSelectionValue?: ActionSelectionDetails;
}

const defaultSelectionValue = {
  selectedItemId: '',
  actionsMenuRef: undefined,
  updateSelectedItem: () => null,
};

/**
 * The ChartTooltip Component
 * @internal
 */
export const _ChartTooltip = forwardRef<
  HTMLDivElement,
  PropsWithChildren<ChartTooltipProps>
>((props, forwardedRef) => {
  const {
    children,
    pinned = false,
    position,
    updatePositionWhenPinned = false,
    actionSelectionValue = defaultSelectionValue,
    onMouseLeave,
    className,
    style,
  } = props;
  const tooltipRef = useRef<HTMLDivElement>(null);
  const mergedRefs = useMergeRefs([forwardedRef, tooltipRef]);

  const { placement, updateTooltipPosition } = useChartTooltip(
    tooltipRef.current,
  );

  const { dataDtrumMask, dataDtrumAllow } = useDataDtrumContext();

  useEffect(() => {
    if (!pinned || updatePositionWhenPinned || isTouchableDevice()) {
      updateTooltipPosition(position);
    }
  }, [
    pinned,
    position.x,
    position.y,
    updatePositionWhenPinned,
    updateTooltipPosition,
  ]);
  const visibility = tooltipRef.current ? 'visible' : 'hidden';
  const chartTooltipContent = (
    <ActionSelectionContext.Provider value={actionSelectionValue}>
      <ChartTooltipMetadataContext.Provider value={{ tooltipRef }}>
        <div
          className={wrapper({ isPinned: pinned })}
          data-testid="chart-tooltip"
          role="tooltip"
          ref={mergedRefs}
          data-placement={placement}
          onMouseLeave={onMouseLeave}
          data-dtrum-mask={dataDtrumMask}
          data-dtrum-allow={dataDtrumAllow}
        >
          <div
            className={clsx(chartTooltip, className)}
            style={{ ...style, visibility }}
          >
            {children}
          </div>
        </div>
      </ChartTooltipMetadataContext.Provider>
    </ActionSelectionContext.Provider>
  );

  return createPortal(chartTooltipContent, document.body);
});

(_ChartTooltip as typeof _ChartTooltip & { displayName: string }).displayName =
  'ChartTooltip';

/**
 * The ChartTooltip Component
 * @internal
 */
export const ChartTooltip = Object.assign(
  _ChartTooltip,
  ChartTooltipSlots,
  ChartTooltipAtoms,
  ChartTooltipTemplate,
);
